import React, {useRef, useState, useEffect} from 'react'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'
import {getDesigner, getSize, /*getDepartment,*/ getCondition, getCategory, getSubCategory, createListing} from '../WebAPI.js'


const ShoppingCartWrapper = styled.div `
display:flex;
width:80%;
margin:0 auto;
justify-content:space-between;
align-items:center;
`

const ItemsPart = styled.div `
width:400px;
`

const InfoPart = styled.div `
width:400px;
`

const ItemsWrapper = styled.div `
display:flex;
flex-direction:column;
`

const Item = styled.div `
width:300px;
height:200px;
border-top:1px solid #1C1C1C;
border-bottom:1px solid #1C1C1C;
font-size:0.9rem;
`

const ItemImage = styled.div `
width:80px;
height:180px;
background-image:url('https://img.ssensemedia.com/images/b_white,g_center,f_auto,q_auto:best/231912M202000_1/butler-svc-ssense-exclusive-blue-formula-hoodie.jpg');
background-position:center;
background-size:cover;
`

const ItemDescription = styled.div `
display:flex;
flex-direction:column;
`

const Title = styled.div `
font-weight:800;
`

const Size = styled.div `
color:grey;
`

const ItemPrice = styled.div  `` 


const OrderTotal = styled.div `
height:60px;
width:100%;
`

const OrderDetail =styled.div `
display:flex;
justify-content:cspace-between;
`

const Detail = styled.div ``

export default function ShoppingCart () {

	return (
		<>
			<Header />
			<Navbar />
			<ShoppingCartWrapper>
				<ItemsPart>
					<ItemsWrapper>
						<Item>
							<ItemImage />
							<ItemDescription>
								<Title>BUTLER SVC</Title>
								<Size>M</Size>
							</ItemDescription>
							<ItemPrice>30000</ItemPrice>
						</Item>
						<OrderTotal>
							<OrderDetail>
								<Detail>Total</Detail>
								<Detail>30000</Detail>
							</OrderDetail>
							<OrderDetail>
								<Detail>Duties & Taxes</Detail>
								<Detail>300</Detail>
							</OrderDetail>
						</OrderTotal>
					</ItemsWrapper>
				</ItemsPart>
				<InfoPart></InfoPart>
			</ShoppingCartWrapper>
		</>	
	)
}
